'use client';

import { useParams, useRouter } from 'next/navigation';
import { useQuery } from '@tanstack/react-query';
import { eventApi } from '@/api/event';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { Spinner } from '@/components/ui/Spinner';
import Image from 'next/image';
import {
    Calendar,
    MapPin,
    Users,
    ArrowLeft,
    Share2,
    Globe,
    Clock,
    Trophy
} from 'lucide-react';
import { formatDate, formatRelativeTime } from '@/lib/utils';
import { useState } from 'react';

export default function EventDetailPage() {
    const params = useParams();
    const router = useRouter();
    const id = params.id as string;
    const [isInterested, setIsInterested] = useState(false);
    const [interestCount, setInterestCount] = useState(0);

    const { data: eventRes, isLoading } = useQuery({
        queryKey: ['event', id],
        queryFn: () => eventApi.getEventById(id),
    });

    const event = eventRes?.data;

    // Use effect to sync state once data is loaded
    if (event && interestCount === 0 && !isLoading) {
        // This is a simple way to sync, ideally use onSuccess/useEffect
        // For brevity in placeholder, we just check if event exists
    }

    if (isLoading) {
        return (
            <div className="flex h-[60vh] items-center justify-center">
                <Spinner size="lg" />
            </div>
        );
    }

    if (!event) {
        return (
            <div className="text-center py-20">
                <h2 className="text-2xl font-bold">Event not found</h2>
                <Button variant="ghost" onClick={() => router.back()}>Go back</Button>
            </div>
        );
    }

    return (
        <div className="mx-auto max-w-5xl space-y-8">
            <button
                onClick={() => router.back()}
                className="flex items-center gap-2 text-sm font-medium text-slate-500 hover:text-indigo-600 transition-colors"
            >
                <ArrowLeft className="h-4 w-4" />
                Back to Events
            </button>

            <div className="grid gap-8 lg:grid-cols-3">
                <div className="lg:col-span-2 space-y-8">
                    <div className="relative aspect-video w-full overflow-hidden rounded-2xl bg-slate-100 shadow-sm">
                        {event.thumbnailUrl ? (
                            <Image src={event.thumbnailUrl} alt={event.title} fill className="object-cover" />
                        ) : (
                            <div className="flex h-full items-center justify-center text-slate-300">
                                <Calendar className="h-20 w-20" />
                            </div>
                        )}
                    </div>

                    <div className="space-y-4">
                        <div className="flex items-center gap-2">
                            <Badge variant={event.type === 'HACKATHON' ? 'success' : 'secondary'} className="px-3 py-1">
                                {event.type}
                            </Badge>
                            <span className="text-sm text-slate-500">Posted {formatRelativeTime(event.createdAt)}</span>
                        </div>
                        <h1 className="text-4xl font-bold text-slate-900">{event.title}</h1>
                        <div className="flex flex-wrap gap-6 text-slate-600">
                            <div className="flex items-center gap-2">
                                <Calendar className="h-5 w-5 text-indigo-500" />
                                <span className="font-medium">{formatDate(event.date)}</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <MapPin className="h-5 w-5 text-indigo-500" />
                                <span className="font-medium">{event.location}</span>
                            </div>
                        </div>
                    </div>

                    <div className="prose prose-slate max-w-none">
                        <h3 className="text-xl font-semibold">About the Event</h3>
                        <p className="text-lg text-slate-600 leading-relaxed">
                            {event.description}
                        </p>
                        {/* More detailed description would go here */}
                        <div className="mt-8 p-6 rounded-xl bg-slate-50 border border-slate-100">
                            <h4 className="font-semibold mb-2">Event Highlights</h4>
                            <ul className="list-disc list-inside space-y-2 text-slate-600">
                                <li>Networking with industry professionals</li>
                                <li>Hands-on workshops and guidance</li>
                                <li>Swag kits and certificates for participants</li>
                                <li>Exclusive access to student community resources</li>
                            </ul>
                        </div>
                    </div>
                </div>

                <div className="space-y-6">
                    <div className="sticky top-24 rounded-2xl border border-slate-200 bg-white p-6 shadow-sm space-y-6">
                        <div className="space-y-4">
                            <div className="flex items-center justify-between text-sm">
                                <span className="text-slate-500 flex items-center gap-1.5">
                                    <Users className="h-4 w-4" />
                                    Interest
                                </span>
                                <span className="font-bold text-slate-900">{event.interestedCount} students</span>
                            </div>
                            <div className="h-2 w-full rounded-full bg-slate-100 overflow-hidden">
                                <div className="h-full bg-indigo-500 rounded-full" style={{ width: '45%' }}></div>
                            </div>
                        </div>

                        <div className="space-y-3">
                            <Button className="w-full gap-2 h-12 text-lg">
                                <Trophy className="h-5 w-5" />
                                Show Interest
                            </Button>
                            <Button variant="outline" className="w-full gap-2 h-12">
                                <Share2 className="h-5 w-5" />
                                Share Event
                            </Button>
                        </div>

                        <div className="pt-6 border-t border-slate-100 space-y-4">
                            <h4 className="font-semibold text-slate-900">Event Details</h4>
                            <div className="space-y-3 text-sm">
                                <div className="flex items-center gap-3 text-slate-600">
                                    <Clock className="h-4 w-4 text-indigo-500" />
                                    <span>Time: 10:00 AM - 4:00 PM</span>
                                </div>
                                <div className="flex items-center gap-3 text-slate-600">
                                    <Globe className="h-4 w-4 text-indigo-500" />
                                    <a href="#" className="hover:text-indigo-600 underline">Official Website</a>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { eventApi } from '@/api/event';
import { EventCard } from '@/components/events/EventCard';
import { Spinner } from '@/components/ui/Spinner';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/Tabs';
import { Search, Calendar as CalendarIcon } from 'lucide-react';

export default function EventsPage() {
    const [activeTab, setActiveTab] = useState('upcoming');
    const [searchQuery, setSearchQuery] = useState('');

    const { data: eventsRes, isLoading } = useQuery({
        queryKey: ['events'],
        queryFn: () => eventApi.getEvents(),
    });

    const events = eventsRes?.data || [];

    // Simple filtering logic
    const filteredEvents = events.filter(event => {
        const matchesSearch = event.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            event.description.toLowerCase().includes(searchQuery.toLowerCase());

        const isUpcoming = new Date(event.date) >= new Date();
        const matchesTab = activeTab === 'upcoming' ? isUpcoming : !isUpcoming;

        return matchesSearch && matchesTab;
    });

    return (
        <div className="space-y-8">
            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900">Events</h1>
                    <p className="text-slate-500">Discover hackathons, workshops, and meetups.</p>
                </div>
            </div>

            <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <div className="flex items-center gap-2 flex-1 max-w-md">
                    <Search className="h-4 w-4 text-slate-400" />
                    <input
                        type="text"
                        placeholder="Search events..."
                        className="flex-1 bg-transparent text-sm outline-none"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>

                <div className="flex items-center gap-4">
                    <div className="flex bg-slate-100 p-1 rounded-lg">
                        <button
                            onClick={() => setActiveTab('upcoming')}
                            className={cn(
                                "px-4 py-1.5 text-sm font-medium rounded-md transition-all",
                                activeTab === 'upcoming' ? "bg-white text-indigo-600 shadow-sm" : "text-slate-500 hover:text-slate-700"
                            )}
                        >
                            Upcoming
                        </button>
                        <button
                            onClick={() => setActiveTab('past')}
                            className={cn(
                                "px-4 py-1.5 text-sm font-medium rounded-md transition-all",
                                activeTab === 'past' ? "bg-white text-indigo-600 shadow-sm" : "text-slate-500 hover:text-slate-700"
                            )}
                        >
                            Past
                        </button>
                    </div>
                </div>
            </div>

            {isLoading ? (
                <div className="flex h-64 items-center justify-center">
                    <Spinner size="lg" />
                </div>
            ) : filteredEvents.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-center rounded-xl border border-dashed border-slate-300 bg-white">
                    <CalendarIcon className="mb-4 h-12 w-12 text-slate-300" />
                    <h3 className="text-lg font-semibold text-slate-900">No events found</h3>
                    <p className="text-slate-500">Try adjusting your search or filters.</p>
                </div>
            ) : (
                <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
                    {filteredEvents.map((event) => (
                        <EventCard key={event.id} event={event} />
                    ))}
                </div>
            )}
        </div>
    );
}

import { cn } from '@/lib/utils';

'use client';

import { useParams, useRouter } from 'next/navigation';
import { useQuery } from '@tanstack/react-query';
import { projectApi } from '@/api/project';
import { teamApi } from '@/api/team';
import { TeamMember } from '@/types';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { Spinner } from '@/components/ui/Spinner';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/Tabs';
import { TeamMemberCard } from '@/components/team/TeamMemberCard';
import { JoinRequestCard } from '@/components/team/JoinRequestCard';
import {
    Github,
    ExternalLink,
    Users,
    Calendar,
    ArrowLeft,
    MoreVertical,
    Trophy,
    MessageSquare,
    ChevronRight
} from 'lucide-react';
import { useAuth } from '@/hooks/useAuth';
import { formatDate } from '@/lib/utils';

export default function ProjectDetailPage() {
    const params = useParams();
    const router = useRouter();
    const { user } = useAuth();
    const id = params.id as string;

    const { data: projectRes, isLoading: isProjectLoading } = useQuery({
        queryKey: ['project', id],
        queryFn: () => projectApi.getProjectById(id),
    });

    const { data: teamRes } = useQuery({
        queryKey: ['team', id],
        queryFn: () => teamApi.getTeamByProjectId(id),
    });

    const project = projectRes?.data;
    const team = teamRes?.data;
    const isOwner = user?.id === project?.ownerId;

    if (isProjectLoading) {
        return (
            <div className="flex h-[60vh] items-center justify-center">
                <Spinner size="lg" />
            </div>
        );
    }

    if (!project) {
        return (
            <div className="text-center py-20">
                <h2 className="text-2xl font-bold">Project not found</h2>
                <Button variant="ghost" onClick={() => router.push('/projects')}>Go to Projects</Button>
            </div>
        );
    }

    return (
        <div className="mx-auto max-w-6xl space-y-8">
            <button
                onClick={() => router.back()}
                className="flex items-center gap-2 text-sm font-medium text-slate-500 hover:text-indigo-600 transition-colors"
            >
                <ArrowLeft className="h-4 w-4" />
                Back
            </button>

            <div className="grid gap-8 lg:grid-cols-3">
                <div className="lg:col-span-2 space-y-8">
                    <div className="space-y-6">
                        <div className="flex items-start justify-between">
                            <div className="space-y-2">
                                <div className="flex items-center gap-2">
                                    <Badge variant={project.status === 'COMPLETED' ? 'success' : 'secondary'}>
                                        {project.status}
                                    </Badge>
                                    <span className="text-sm text-slate-500 flex items-center gap-1">
                                        <Calendar className="h-3 w-3" />
                                        Created {formatDate(project.createdAt)}
                                    </span>
                                </div>
                                <h1 className="text-4xl font-bold text-slate-900">{project.title}</h1>
                            </div>
                            {isOwner && (
                                <Button variant="outline" size="sm">Edit Project</Button>
                            )}
                        </div>

                        <div className="flex flex-wrap gap-4">
                            {project.techStack.map(tech => (
                                <Badge key={tech} variant="outline" className="bg-slate-50">
                                    {tech}
                                </Badge>
                            ))}
                        </div>

                        <div className="prose prose-slate max-w-none">
                            <h3 className="text-xl font-semibold">About this project</h3>
                            <p className="text-slate-600 leading-relaxed whitespace-pre-wrap">
                                {project.description}
                            </p>
                        </div>
                    </div>

                    <Tabs defaultValue="team">
                        <TabsList className="w-full justify-start border-b border-slate-200 bg-transparent rounded-none p-0 h-auto gap-8">
                            <TabsTrigger
                                value="team"
                                className="rounded-none border-b-2 border-transparent data-[state=active]:border-indigo-600 bg-transparent shadow-none px-0 py-2"
                            >
                                Team ({team?.members.length || 0})
                            </TabsTrigger>
                            <TabsTrigger
                                value="showcase"
                                className="rounded-none border-b-2 border-transparent data-[state=active]:border-indigo-600 bg-transparent shadow-none px-0 py-2"
                            >
                                Showcase
                            </TabsTrigger>
                        </TabsList>

                        <TabsContent value="team" className="pt-6 space-y-6">
                            <div className="grid gap-4 sm:grid-cols-2">
                                {team?.members.map((member: TeamMember) => (
                                    <TeamMemberCard key={member.userId} member={member} />
                                ))}
                            </div>

                            {isOwner && (
                                <div className="space-y-4 pt-6">
                                    <h4 className="font-semibold text-slate-900 flex items-center gap-2">
                                        Pending Requests
                                        <Badge variant="secondary" className="rounded-full h-5 w-5 flex items-center justify-center p-0">3</Badge>
                                    </h4>
                                    <div className="grid gap-4 sm:grid-cols-2">
                                        {/* Placeholder requests if teamApi doesn't have a specific getRequests call yet */}
                                        <div className="col-span-full text-sm text-slate-500 italic">
                                            No pending requests at the moment.
                                        </div>
                                    </div>
                                </div>
                            )}
                        </TabsContent>
                    </Tabs>
                </div>

                <div className="space-y-6">
                    <div className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm space-y-6">
                        <h4 className="font-semibold text-slate-900">Project Links</h4>
                        <div className="space-y-3">
                            {project.githubUrl && (
                                <a
                                    href={project.githubUrl}
                                    target="_blank"
                                    className="flex items-center justify-between p-3 rounded-lg border border-slate-100 hover:bg-slate-50 transition-colors"
                                >
                                    <div className="flex items-center gap-3">
                                        <Github className="h-5 w-5" />
                                        <span className="text-sm font-medium">Repository</span>
                                    </div>
                                    <ExternalLink className="h-4 w-4 text-slate-400" />
                                </a>
                            )}
                            {project.liveUrl && (
                                <a
                                    href={project.liveUrl}
                                    target="_blank"
                                    className="flex items-center justify-between p-3 rounded-lg border border-slate-100 hover:bg-slate-50 transition-colors"
                                >
                                    <div className="flex items-center gap-3">
                                        <Trophy className="h-5 w-5 text-amber-500" />
                                        <span className="text-sm font-medium">Live Demo</span>
                                    </div>
                                    <ExternalLink className="h-4 w-4 text-slate-400" />
                                </a>
                            )}
                        </div>

                        {!isOwner && (
                            <div className="pt-6 border-t border-slate-100 space-y-4">
                                <div className="flex items-center justify-between text-sm mb-4">
                                    <span className="text-slate-500">Team Capacity</span>
                                    <span className="font-bold">{team?.members.length || 0} / {team?.capacity || 4}</span>
                                </div>
                                <Button className="w-full gap-2" variant="primary">
                                    Join Project
                                    <ChevronRight className="h-4 w-4" />
                                </Button>
                                <Button className="w-full gap-2" variant="outline">
                                    <MessageSquare className="h-4 w-4" />
                                    Ask a Question
                                </Button>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}
